CREATE TABLE t0 (c0, c2, c3);
SELECT subq10.c17 AS c8, subq10.c14 AS c12 FROM (SELECT subq9.c8 AS c14, TRUE AS c16, subq9.c10 AS c17 FROM (SELECT t59.c3 AS c4, t59.c3 AS c6, t59.c2 AS c8, t59.c0 AS c10, t59.c3 AS c12 FROM t0 AS t59 LEFT OUTER JOIN t0 AS t60 ON (NOT t59.c3 IS NULL) ORDER BY c4) AS subq9 ORDER BY c16 ASC) AS subq10 WHERE subq10.c17 = CASE subq10.c16 WHEN subq10.c16 IS NULL THEN subq10.c16 ELSE subq10.c16 END LIMIT 414725328173764698